patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -8,7 +8,7 @@
   output reg [7:0] mux_out
 );

-  always @(sel)
+  always @(sel or in0 or in1 or in2 or in3)
   begin
     case(sel)
       2'b00: mux_out = in0;

before_code:
module multiplexer_8bit (
  input [7:0] in0,
  input [7:0] in1,
  input [7:0] in2,
  input [7:0] in3,
  input [1:0] sel,
  output reg [7:0] mux_out
);

  always @(sel)
  begin
    case(sel)
      2'b00: mux_out = in0;
      2'b01: mux_out = in1;
      2'b10: mux_out = in2;
      2'b11: mux_out = in3;
      default: mux_out = 8'b0;
    endcase
  end

endmodule

after_code:
module multiplexer_8bit (
  input [7:0] in0,
  input [7:0] in1,
  input [7:0] in2,
  input [7:0] in3,
  input [1:0] sel,
  output reg [7:0] mux_out
);

  always @(sel or in0 or in1 or in2 or in3)
  begin
    case(sel)
      2'b00: mux_out = in0;
      2'b01: mux_out = in1;
      2'b10: mux_out = in2;
      2'b11: mux_out = in3;
      default: mux_out = 8'b0;
    endcase
  end

endmodule
